INSERT INTO genres (aliases, api_detail_url, count_of_isssue_appearances, date_added, date_last_updated, deck, description, first_appeared_in_issue, id, image, name, site_detail_url, start_year) VALUES ('Variant Cover: Marvel Apes', 'https://comicvine.gamespot.com/api/concept/4015-56107/', '46', '2012-04-22 16:01:30', '2025-06-24 12:14:43', 'A series of Marvel Apes themed variant covers that were released during the run of the miniseries.', NULL, '{''api_detail_url'': ''https://comicvine.gamespot.com/api/first_appeared_in_issue/4000-268928/'', ''id'': 268928, ''name'': ''A Look Back'', ''issue_number'': ''1''}', '56107', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/0/9241/557318-0004.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/0/9241/557318-0004.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/0/9241/557318-0004.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/0/9241/557318-0004.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/0/9241/557318-0004.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/0/9241/557318-0004.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/0/9241/557318-0004.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/0/9241/557318-0004.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/0/9241/557318-0004.jpg'', ''image_tags'': ''All Images''}', 'Variant Theme: Marvel Apes', 'https://comicvine.gamespot.com/variant-theme-marvel-apes/4015-56107/', '2008');
