INSERT INTO genres (aliases, api_detail_url, count_of_isssue_appearances, date_added, date_last_updated, deck, description, first_appeared_in_issue, id, image, name, site_detail_url, start_year) VALUES (NULL, 'https://comicvine.gamespot.com/api/concept/4015-56142/', '28', '2012-09-07 18:14:03', '2020-02-14 13:59:29', 'In December 2001, Marvel President Bill Jemas and Editor-in-Chief Joe Quesada hatched a new gimmick: for a month one issue of most of their books would feature absolutely no dialogue and rely entirely on art for the purposes of telling a story.', '<figure data-align="right" data-embed-type="image" data-img-src="https://static.comicvine.com/uploads/original/7/70215/2746306-2621479-gi_joe__1982_marvel__21_super.jpeg" data-ref-id="1300-2746306" data-size="small" data-ratio="1.54"><a class="fluid-height" style="padding-bottom:154.0%" href="https://static.comicvine.com/uploads/original/7/70215/2746306-2621479-gi_joe__1982_marvel__21_super.jpeg" data-ref-id="1300-2746306"><img alt="No Caption Provided" src="https://comicvine.gamespot.com/a/uploads/scale_small/7/70215/2746306-2621479-gi_joe__1982_marvel__21_super.jpeg" srcset="https://comicvine.gamespot.com/a/uploads/original/7/70215/2746306-2621479-gi_joe__1982_marvel__21_super.jpeg 600w, https://comicvine.gamespot.com/a/uploads/scale_medium/7/70215/2746306-2621479-gi_joe__1982_marvel__21_super.jpeg 480w, https://comicvine.gamespot.com/a/uploads/scale_small/7/70215/2746306-2621479-gi_joe__1982_marvel__21_super.jpeg 320w" sizes="(max-width: 320px) 100vw, 320px" data-width="320"></a></figure><p>This challenge was inspired by <a data-ref-id="4000-113726" href="/gi-joe-a-real-american-hero-silent-interlude/4000-113726/" slug="gi-joe-a-real-american-hero-silent-interlude">G.I. Joe: A Real American Hero #21</a>, a popular silent issue from 1984. It was further propelled by the debate over who is more needed in comics, to tell the story: the writer or the artist? You can write a novel without an artist, but the artist is an essential part of the process for comics. So when Quesada came up with this idea in 2002, he was saying, "Okay, artists, let''s see what you''ve got." Some had better success than others, but it was an interesting experiment.</p><h2>Collected Editions:</h2><p><a data-ref-id="4050-21951" href="/nuff-said/4050-21951/" slug="nuff-said">''Nuff Said</a> (Collects: Inc. Hulk #35, New X-Men #121, PP: Spider-Man #38; Amz. Spider-Man #39 (480), Punisher #7, Thor #44, X-Force #123.</p>', '{''api_detail_url'': ''https://comicvine.gamespot.com/api/first_appeared_in_issue/4000-65192/'', ''id'': 65192, ''name'': ''Golden'', ''issue_number'': ''401''}', '56142', '{''icon_url'': ''https://comicvine.gamespot.com/a/uploads/square_avatar/11/117763/2579553-nuff.jpg'', ''medium_url'': ''https://comicvine.gamespot.com/a/uploads/scale_medium/11/117763/2579553-nuff.jpg'', ''screen_url'': ''https://comicvine.gamespot.com/a/uploads/screen_medium/11/117763/2579553-nuff.jpg'', ''screen_large_url'': ''https://comicvine.gamespot.com/a/uploads/screen_kubrick/11/117763/2579553-nuff.jpg'', ''small_url'': ''https://comicvine.gamespot.com/a/uploads/scale_small/11/117763/2579553-nuff.jpg'', ''super_url'': ''https://comicvine.gamespot.com/a/uploads/scale_large/11/117763/2579553-nuff.jpg'', ''thumb_url'': ''https://comicvine.gamespot.com/a/uploads/scale_avatar/11/117763/2579553-nuff.jpg'', ''tiny_url'': ''https://comicvine.gamespot.com/a/uploads/square_mini/11/117763/2579553-nuff.jpg'', ''original_url'': ''https://comicvine.gamespot.com/a/uploads/original/11/117763/2579553-nuff.jpg'', ''image_tags'': ''All Images''}', '''Nuff Said', 'https://comicvine.gamespot.com/nuff-said/4015-56142/', '2002');
